export function getExtraComparisons(): Record<string, ComparisonPageData> {
  const result: Record<string, ComparisonPageData> = {};
  DEFS.forEach((def, idx) => {
    result[def.slug] = build(def, idx);
  });
  return result;
}

export function getExtraTrendingData(): { slug: string; title: string; category: string; viewCount: number }[] {
  return DEFS.map((d) => ({ slug: d.slug, title: d.title, category: d.category, viewCount: d.views }))
    .sort((a, b) => b.viewCount - a.viewCount);
}
